"use client";

import { ReactNode, useEffect, useRef } from "react";
import { useQuery } from "@tanstack/react-query";
import { useRouter } from "next/navigation";
import { Box, CircularProgress, Typography } from "@mui/material";

import { AppShell } from "@/components/layout/app-shell";
import { startRouteTiming } from "@/lib/performance";
import { getCurrentUser } from "@/services/session";
import { CurrentUser } from "@/services/types";

export default function AuthenticatedLayout({ children }: { children: ReactNode }) {
  const router = useRouter();
  const endTimingRef = useRef<(() => number) | null>(null);
  const sessionQuery = useQuery<CurrentUser | null>({
    queryKey: ["current-user"],
    queryFn: getCurrentUser,
    retry: false,
    staleTime: 5 * 60_000
  });

  useEffect(() => {
    endTimingRef.current = startRouteTiming("/authenticated-shell");
    return () => {
      if (endTimingRef.current) {
        endTimingRef.current();
        endTimingRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (sessionQuery.isLoading) return;
    if (!sessionQuery.data) {
      router.replace("/login");
    }
    if (endTimingRef.current) {
      endTimingRef.current();
      endTimingRef.current = null;
    }
  }, [router, sessionQuery.data, sessionQuery.isLoading]);

  if (sessionQuery.isLoading) {
    return (
      <Box sx={{ minHeight: "100dvh", display: "grid", placeItems: "center", gap: 1 }}>
        <CircularProgress size={30} />
        <Typography color="text.secondary">Loading session...</Typography>
      </Box>
    );
  }

  if (!sessionQuery.data) return null;

  return <AppShell user={sessionQuery.data}>{children}</AppShell>;
}
