"use client";

import { useEffect, useState } from "react";
import { useMediaQuery, useTheme } from "@mui/material";

export function useResponsiveNav() {
  const theme = useTheme();
  const desktopMatch = useMediaQuery(theme.breakpoints.up("lg"));
  const [hydrated, setHydrated] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    setHydrated(true);
  }, []);

  const desktop = hydrated ? desktopMatch : false;

  useEffect(() => {
    if (desktop) {
      setMobileOpen(false);
    }
  }, [desktop]);

  return {
    desktop,
    mobileOpen,
    openMobileNav: () => setMobileOpen(true),
    closeMobileNav: () => setMobileOpen(false),
    toggleMobileNav: () => setMobileOpen((open) => !open)
  };
}
