"use client";

import { ReactNode, useEffect, useState } from "react";
import { usePathname, useRouter } from "next/navigation";
import { Box, Container, Toolbar } from "@mui/material";

import { AppHeader } from "@/components/layout/app-header";
import { SidebarNav } from "@/components/layout/sidebar-nav";
import { drawerWidth } from "@/lib/mui-theme";
import { useResponsiveNav } from "@/lib/use-responsive-nav";
import { logout } from "@/services/auth";
import { CurrentUser } from "@/services/types";

export function AppShell({
  user,
  children
}: {
  user: CurrentUser;
  children: ReactNode;
}) {
  const router = useRouter();
  const pathname = usePathname();
  const nav = useResponsiveNav();
  const activeYear = pathname.match(/^\/years\/(\d{4})$/)?.[1] ?? "2026";
  const [plannerYear, setPlannerYear] = useState(activeYear);
  const plannerHref = `/years/${plannerYear}`;

  useEffect(() => {
    if (pathname.match(/^\/years\/\d{4}$/)) {
      setPlannerYear(activeYear);
      return;
    }
    setPlannerYear(String(new Date().getFullYear()));
  }, [activeYear, pathname]);

  useEffect(() => {
    router.prefetch(plannerHref);
    router.prefetch("/activity");
  }, [plannerHref, router]);

  async function handleLogout() {
    await logout();
    nav.closeMobileNav();
    router.push("/login");
    router.refresh();
  }

  return (
    <Box sx={{ display: "flex", minHeight: "100dvh", bgcolor: "background.default" }}>
      <SidebarNav
        currentPath={pathname}
        desktop={nav.desktop}
        mobileOpen={nav.mobileOpen}
        plannerHref={plannerHref}
        onCloseMobile={nav.closeMobileNav}
        onSignOut={handleLogout}
      />
      <Box
        component="main"
        sx={{
          display: "flex",
          flexDirection: "column",
          flexGrow: 1,
          minWidth: 0,
          ml: { lg: `${drawerWidth}px` }
        }}
      >
        <AppHeader
          user={user}
          showMenuButton={!nav.desktop}
          onMenuClick={nav.toggleMobileNav}
        />
        <Toolbar />
        <Container maxWidth="xl" sx={{ py: 3 }}>
          {children}
        </Container>
      </Box>
    </Box>
  );
}
